import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: (project_basename, framework, package_id) -> resolvedVersion
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        name = proj['path'].rsplit('/',1)[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                lookup[(name, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv == av:
        unchanged.append(k + (bv,))
    else:
        changes.append(k + (bv, av))

print('=== CHANGES ===')
for proj, fw, pkg, bv, av in changes:
    print(f'{proj} | {fw} | {pkg} | {bv} -> {av}')

print()
print('=== UNCHANGED ===')
for proj, fw, pkg, v in unchanged:
    print(f'{proj} | {fw} | {pkg} | {v}')
